from pydantic_ai import tool, Context
from pydantic import BaseModel, validator
import spacy

class ContextCoverage(BaseModel):
    query_entities: set[str]
    context_entities: set[str]
    coverage_ratio: float = Field(..., ge=0.8)

nlp = spacy.load('en_core_web_sm')

@rag_agent.tool
def check_context_coverage(query: str, context: str) -> ContextCoverage:
    query_doc = nlp(query)
    context_doc = nlp(context)
    query_entities = {ent.text.lower() for ent in query_doc.ents}
    context_entities = {ent.text.lower() for ent in context_doc.ents}
    coverage = len(query_entities.intersection(context_entities)) / len(query_entities)
    return ContextCoverage(
        query_entities=query_entities,
        context_entities=context_entities,
        coverage_ratio=coverage
    )

from pydantic_ai import Agent
from pydantic import BaseModel, Field, validator

class ChunkQuality(BaseModel):
    chunks: list[str]
    complete_sentences: bool = True
    avg_length: float = Field(..., ge=100)

    @validator('chunks')
    def validate_completeness(cls, v):
        for chunk in v:
            if not chunk.strip().endswith(('.', '!', '?')):
                raise ValueError('Incomplete chunk detected')
        return v

@rag_agent.result_validator
def validate_chunk_quality(result: ChunkQuality) -> ChunkQuality:
    lengths = [len(chunk) for chunk in result.chunks]
    result.avg_length = np.mean(lengths)
    if result.avg_length < 100:
        raise ValueError('Chunks too short - truncation detected')
    return result

