from pydantic_ai import Agent, tool
from typing import Dict, Any

class RAGOptimizer:
    def __init__(self):
        self.overlap = 0.2
        self.max_overlap = 0.5

    @tool
    def optimize_retrieval(self, query: str, failed_validation: str) -> Dict[str, Any]:
        if 'insufficient context' in failed_validation.lower():
            self.overlap = min(self.max_overlap, self.overlap + 0.1)
        return {'recommended_overlap': self.overlap, 'query': query}

rag_optimizer = RAGOptimizer()
rag_agent = Agent('optimized-rag', tools=[rag_optimizer.optimize_retrieval])

